package org.eclipse.rdf4j.sail.lmdb;

import static org.junit.jupiter.api.Assertions.assertArrayEquals;
import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertSame;
import static org.junit.jupiter.api.Assertions.fail;

import java.io.File;
import java.io.IOException;
import java.lang.reflect.Field;
import java.nio.ByteBuffer;
import java.util.List;

import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

/**
 * Focused tests that directly exercise TripleIndex#toKey to provide coverage for behavior-neutral optimizations such as
 * internal key encoding caching.
 */
class TripleIndexToKeyCacheTest {

	private TripleStore tripleStore;
	private File dataDir;

	@BeforeEach
	void setup(@TempDir File dataDir) throws Exception {
		this.dataDir = dataDir;
		// Create a small store; index set is irrelevant for constructing standalone TripleIndex instances
		tripleStore = new TripleStore(dataDir, new LmdbStoreConfig("spoc,posc"), null);
	}

	@AfterEach
	void tearDown() throws Exception {
		if (tripleStore != null) {
			tripleStore.close();
		}
		LmdbTestUtil.deleteDir(dataDir);
	}

	@Test
	void spoc_subjectBound_othersWildcard() throws Exception {
		// Given: only subject is bound, others are wildcards (Long.MAX_VALUE)
		long subj = 123L;
		long pred = Long.MAX_VALUE;
		long obj = Long.MAX_VALUE;
		long context = Long.MAX_VALUE;

		tripleStore.startTransaction();
		TripleIndex index = new TripleIndex("spoc", "spoc", true, tripleStore.env, tripleStore.writeTxn);
		tripleStore.endTransaction(true);

		int len = Varint.calcListLengthUnsigned(subj, pred, obj, context);
		ByteBuffer actual = ByteBuffer.allocate(len);
		index.toKey(actual, subj, pred, obj, context);
		actual.flip();

		// Expected: varints in spoc order
		ByteBuffer expected = ByteBuffer.allocate(len);
		Varint.writeUnsigned(expected, subj);
		Varint.writeUnsigned(expected, pred);
		Varint.writeUnsigned(expected, obj);
		Varint.writeUnsigned(expected, context);
		expected.flip();

		assertArrayEquals(expected.array(), actual.array());
	}

	@Test
	void posc_predicateBound_othersWildcard() throws Exception {
		// Given: only predicate is bound, others are wildcards (Long.MAX_VALUE)
		long subj = Long.MAX_VALUE;
		long pred = 456L;
		long obj = Long.MAX_VALUE;
		long context = Long.MAX_VALUE;

		tripleStore.startTransaction();
		TripleIndex index = new TripleIndex("posc", "posc", true, tripleStore.env, tripleStore.writeTxn);
		tripleStore.endTransaction(true);

		int len = Varint.calcListLengthUnsigned(subj, pred, obj, context);
		ByteBuffer actual = ByteBuffer.allocate(len);
		index.toKey(actual, subj, pred, obj, context);
		actual.flip();

		// Expected: varints in posc order
		ByteBuffer expected = ByteBuffer.allocate(len);
		Varint.writeUnsigned(expected, pred);
		Varint.writeUnsigned(expected, obj);
		Varint.writeUnsigned(expected, subj);
		Varint.writeUnsigned(expected, context);
		expected.flip();

		assertArrayEquals(expected.array(), actual.array());
	}

	@Test
	void patternScoreUsesConstructorFieldSequence() throws Exception {
		tripleStore.startTransaction();
		TripleIndex index = tripleStore.createIndexForTesting("spoc");
		tripleStore.endTransaction(true);

		char[] fieldSeq = index.getFieldSeq();
		fieldSeq[0] = 'p';
		fieldSeq[1] = 's';

		assertEquals(1, index.getPatternScore(123L, -1L, -1L, -1L));
		assertEquals(0, index.getPatternScore(-1L, 456L, -1L, -1L));
	}

	@Test
	void patternScoreMatchesFieldSequencePrefix() throws Exception {
		String[] fieldSequences = { "spoc", "spco", "sopc", "socp", "scpo", "scop", "psoc", "psco", "posc",
				"pocs", "pcso", "pcos", "ospc", "oscp", "opsc", "opcs", "ocsp", "ocps", "cspo", "csop",
				"cpso", "cpos", "cosp", "cops" };
		long[][] patterns = { { -1L, -1L, -1L, -1L }, { 1L, -1L, -1L, -1L }, { -1L, 2L, -1L, -1L },
				{ -1L, -1L, 3L, -1L }, { -1L, -1L, -1L, 0L }, { 1L, 2L, -1L, -1L },
				{ 1L, -1L, 3L, 0L }, { 1L, 2L, 3L, 0L } };

		for (String fieldSequence : fieldSequences) {
			tripleStore.startTransaction();
			TripleIndex index = tripleStore.createIndexForTesting(fieldSequence);
			tripleStore.endTransaction(true);
			for (long[] pattern : patterns) {
				assertEquals(expectedPatternScore(fieldSequence, pattern[0], pattern[1], pattern[2], pattern[3]),
						index.getPatternScore(pattern[0], pattern[1], pattern[2], pattern[3]), fieldSequence);
			}
		}
	}

	@Test
	void bestIndexStopsAfterPerfectScore() throws Exception {
		tripleStore.startTransaction();
		TripleIndex perfectIndex = new FixedScoreTripleIndex(tripleStore, "spoc", 4, false);
		TripleIndex laterIndex = new FixedScoreTripleIndex(tripleStore, "posc", 0, true);
		tripleStore.endTransaction(true);

		List<TripleIndex> indexes = getIndexes();
		indexes.clear();
		indexes.add(perfectIndex);
		indexes.add(laterIndex);

		assertSame(perfectIndex, tripleStore.getBestIndex(1L, 2L, 3L, 0L));
	}

	private int expectedPatternScore(String fieldSequence, long subj, long pred, long obj, long context) {
		int score = 0;
		for (int i = 0; i < fieldSequence.length(); i++) {
			long value = switch (fieldSequence.charAt(i)) {
			case 's' -> subj;
			case 'p' -> pred;
			case 'o' -> obj;
			case 'c' -> context;
			default -> throw new IllegalArgumentException(fieldSequence);
			};
			if (value < 0) {
				return score;
			}
			score++;
		}
		return score;
	}

	@SuppressWarnings("unchecked")
	private List<TripleIndex> getIndexes() throws Exception {
		Field indexesField = TripleStore.class.getDeclaredField("indexes");
		indexesField.setAccessible(true);
		return (List<TripleIndex>) indexesField.get(tripleStore);
	}

	private static class FixedScoreTripleIndex extends TripleIndex {

		private final int score;
		private final boolean failOnScore;

		FixedScoreTripleIndex(TripleStore store, String fieldSeq, int score, boolean failOnScore) throws Exception {
			super("test-" + fieldSeq, fieldSeq, false, longField(store, "env"), longField(store, "writeTxn"));
			this.score = score;
			this.failOnScore = failOnScore;
		}

		private static long longField(TripleStore store, String name) throws Exception {
			Field field = TripleStore.class.getDeclaredField(name);
			field.setAccessible(true);
			return field.getLong(store);
		}

		@Override
		public int getPatternScore(long subj, long pred, long obj, long context) {
			if (failOnScore) {
				fail("A perfect score should stop index scoring");
			}
			return score;
		}
	}
}
